from dataclasses import dataclass
from typing import Optional, Union
from datetime import datetime
from enum import Enum

# GraphState never generates time.
# Execution timestamps are generated by the Runner.
# Domain-specific timestamps may be provided by Nodes.


class EventType(str, Enum):
    """Canonical event types emitted during execution."""
    NODE_STARTED = "node_started"
    NODE_COMPLETED = "node_completed"
    NODE_SKIPPED = "node_skipped"


@dataclass(frozen=True)
class Fact:
    key: str
    value: Union[str, int, float, bool]
    source: str
    timestamp: datetime

    def to_dict(self) -> dict:
        return {
            "key": self.key,
            "value": self.value,
            "source": self.source,
            "timestamp": self.timestamp.isoformat(),
        }

    @classmethod
    def from_dict(cls, data: dict) -> "Fact":
        return cls(
            key=data["key"],
            value=data["value"],
            source=data["source"],
            timestamp=datetime.fromisoformat(data["timestamp"]),
        )


@dataclass(frozen=True)
class Decision:
    description: str
    timestamp: datetime

    def to_dict(self) -> dict:
        return {
            "description": self.description,
            "timestamp": self.timestamp.isoformat(),
        }

    @classmethod
    def from_dict(cls, data: dict) -> "Decision":
        return cls(
            description=data["description"],
            timestamp=datetime.fromisoformat(data["timestamp"]),
        )


@dataclass(frozen=True)
class Rejection:
    description: str
    reason: str
    timestamp: datetime

    def to_dict(self) -> dict:
        return {
            "description": self.description,
            "reason": self.reason,
            "timestamp": self.timestamp.isoformat(),
        }

    @classmethod
    def from_dict(cls, data: dict) -> "Rejection":
        return cls(
            description=data["description"],
            reason=data["reason"],
            timestamp=datetime.fromisoformat(data["timestamp"]),
        )


@dataclass(frozen=True)
class Event:
    event_type: EventType
    description: str
    timestamp: datetime
    metadata: Optional[dict] = None
    node_name: Optional[str] = None

    def to_dict(self) -> dict:
        return {
            "event_type": self.event_type.value,
            "description": self.description,
            "timestamp": self.timestamp.isoformat(),
            "metadata": self.metadata,
            "node_name": self.node_name,
        }

    @classmethod
    def from_dict(cls, data: dict) -> "Event":
        return cls(
            event_type=EventType(data["event_type"]),
            description=data["description"],
            timestamp=datetime.fromisoformat(data["timestamp"]),
            metadata=data.get("metadata"),
            node_name=data.get("node_name"),
        )


@dataclass(frozen=True)
class GraphState:
    trace_id: str
    intent: Optional[str]
    facts: tuple[Fact, ...]
    decisions: tuple[Decision, ...]
    rejections: tuple[Rejection, ...]
    events: tuple[Event, ...]

    def to_dict(self) -> dict:
        return {
            "trace_id": self.trace_id,
            "intent": self.intent,
            "facts": [f.to_dict() for f in self.facts],
            "decisions": [d.to_dict() for d in self.decisions],
            "rejections": [r.to_dict() for r in self.rejections],
            "events": [e.to_dict() for e in self.events],
        }

    @classmethod
    def from_dict(cls, data: dict) -> "GraphState":
        return cls(
            trace_id=data["trace_id"],
            intent=data.get("intent"),
            facts=tuple(Fact.from_dict(f) for f in data.get("facts", [])),
            decisions=tuple(Decision.from_dict(d) for d in data.get("decisions", [])),
            rejections=tuple(Rejection.from_dict(r) for r in data.get("rejections", [])),
            events=tuple(Event.from_dict(e) for e in data.get("events", [])),
        )

    def with_intent(self, intent: str) -> "GraphState":
        return GraphState(
            trace_id=self.trace_id,
            intent=intent,
            facts=self.facts,
            decisions=self.decisions,
            rejections=self.rejections,
            events=self.events,
        )

    def with_fact(self, fact: Fact) -> "GraphState":
        return GraphState(
            trace_id=self.trace_id,
            intent=self.intent,
            facts=self.facts + (fact,),
            decisions=self.decisions,
            rejections=self.rejections,
            events=self.events,
        )

    def with_decision(self, decision: Decision) -> "GraphState":
        return GraphState(
            trace_id=self.trace_id,
            intent=self.intent,
            facts=self.facts,
            decisions=self.decisions + (decision,),
            rejections=self.rejections,
            events=self.events,
        )

    def with_rejection(self, rejection: Rejection) -> "GraphState":
        return GraphState(
            trace_id=self.trace_id,
            intent=self.intent,
            facts=self.facts,
            decisions=self.decisions,
            rejections=self.rejections + (rejection,),
            events=self.events,
        )

    def with_event(self, event: Event) -> "GraphState":
        return GraphState(
            trace_id=self.trace_id,
            intent=self.intent,
            facts=self.facts,
            decisions=self.decisions,
            rejections=self.rejections,
            events=self.events + (event,),
        )

    @staticmethod
    def empty(trace_id: str) -> "GraphState":
        return GraphState(
            trace_id=trace_id,
            intent=None,
            facts=(),
            decisions=(),
            rejections=(),
            events=(),
        )
